  const [details, setDetails] = useState<StyleDetail[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopying, setIsCopying] = useState(false);

  const loadData = async () => {
    setLoading(true);
    const data = await fetchStyleLibrary();
    setStyles(data);
    setLoading(false);
  };

  useEffect(() => { loadData(); }, []);

  const toggleExpand = (id: string) => {
    setExpandedStyles(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleOpenCreate = () => {
    setEditingStyle({ style_no: '', category: 'Casuals', pcs_per_box: 1, packing_type: 'cover' });
    const initialDetails: StyleDetail[] = [];
    SECTIONS.forEach(section => {
      DEFAULT_TOPICS[section].forEach(label => {
        initialDetails.push({ section, label, content_text: '', attachments: [] });
      });
    });
    setDetails(initialDetails);
    setIsEditorOpen(true);
  };

  const handleEdit = (style: StyleLibrary) => {
    setEditingStyle(style);
    setDetails(style.details || []);
    setIsEditorOpen(true);
  };

  const handleCopyFrom = (sourceStyle: StyleLibrary) => {
    if (!editingStyle) return;
    const copiedDetails = sourceStyle.details?.map(d => ({
      ...d,
      id: undefined,
      style_id: undefined
    })) || [];
    setDetails(copiedDetails);
    setIsCopying(false);
  };

  const addCustomTopic = (section: string) => {
    setDetails([...details, { section, label: 'New Topic', content_text: '', attachments: [] }]);
  };

  const removeDetail = (index: number) => {
    setDetails(details.filter((_, i) => i !== index));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, detailIndex: number) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const updated = [...details];
    for (const file of Array.from(files)) {
      const url = await uploadOrderAttachment(file);
      if (url) {
        updated[detailIndex].attachments.push({
          name: file.name,
          url,
          type: file.type.startsWith('image/') ? 'image' : 'document'
        });
      }
    }
    setDetails(updated);
  };

  const handleSave = async () => {
    if (!editingStyle?.style_no) return alert("Style Number is required");
    setIsSubmitting(true);
    const result = await upsertStyle(editingStyle, details);
    if (result.error) alert(result.error);
    else {
      setIsEditorOpen(false);
      loadData();
    }
    setIsSubmitting(false);
  };

  const handleDelete = async (id: string) => {
    if (confirm("Delete this style master?")) {
      await deleteStyle(id);
      loadData();
    }
  };

  const handlePrintStyle = (style: StyleLibrary) => {
    const win = window.open('', 'PrintStyle', 'width=1000,height=800');
    if (!win) return;

    const sectionsHtml = SECTIONS.map(section => {
      const sectionDetails = style.details?.filter(d => d.section === section) || [];
      if (sectionDetails.length === 0) return '';

      return `
        <div class="print-section">
          <h2 class="section-title">${section}</h2>
          <div class="details-grid">
            ${sectionDetails.map(d => `
              <div class="detail-box">
                <div class="detail-label">${d.label}</div>
                <div class="detail-content">${d.content_text || '---'}</div>
                ${d.attachments.length > 0 ? `
                  <div class="attachment-gallery">
                    ${d.attachments.map(a => a.type === 'image' 
                      ? `<div class="img-container"><img src="${a.url}" /><div class="img-name">${a.name}</div></div>`
                      : `<div class="doc-link">📄 ${a.name}</div>`
                    ).join('')}
                  </div>
                ` : ''}
              </div>
            `).join('')}
          </div>
        </div>
      `;
    }).join('');

    win.document.write(`
      <html><head><title>Style Report - ${style.style_no}</title>
      <style>
        @media print { body { -webkit-print-color-adjust: exact; } }
        body { font-family: system-ui, sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; }
        .header { border-bottom: 4px solid #1e293b; padding-bottom: 20px; margin-bottom: 30px; display: flex; justify-content: space-between; align-items: flex-end; }
        .style-no { font-size: 42px; font-weight: 900; margin: 0; color: #4f46e5; }
        .category { font-size: 18px; font-weight: bold; color: #64748b; text-transform: uppercase; }
        .section-title { background: #f1f5f9; padding: 10px 15px; border-left: 5px solid #4f46e5; margin: 40px 0 20px 0; font-size: 20px; font-weight: 800; text-transform: uppercase; }
        .detail-box { margin-bottom: 25px; border: 1px solid #e2e8f0; padding: 20px; border-radius: 8px; page-break-inside: avoid; }
        .detail-label { font-weight: 900; font-size: 14px; text-transform: uppercase; color: #475569; border-bottom: 1px solid #f1f5f9; padding-bottom: 5px; margin-bottom: 10px; }
        .detail-content { font-size: 16px; color: #0f172a; white-space: pre-wrap; }
        .attachment-gallery { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-top: 15px; }
        .img-container { border: 1px solid #ddd; padding: 5px; border-radius: 4px; text-align: center; }
        .img-container img { max-width: 100%; max-height: 400px; border-radius: 2px; }
        .img-name { font-size: 10px; color: #94a3b8; margin-top: 5px; }
        .doc-link { background: #f8fafc; padding: 8px; border-radius: 4px; font-size: 12px; font-weight: bold; border: 1px solid #e2e8f0; }
      </style>
      </head><body>
        <div class="header">
          <div><h1 class="style-no">STYLE: ${style.style_no}</h1><div class="category">${style.category} Master Library</div></div>
          <div style="text-align: right; font-size: 12px; color: #64748b;">Printed on: ${new Date().toLocaleString()}</div>
        </div>
        ${sectionsHtml}
      </body></html>
    `);
    win.document.close();
    setTimeout(() => { win.print(); }, 1000);
  };

  const filteredStyles = styles.filter(s => 
    s.style_no.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg">
              <Library size={28}/> 
            </div>
            Style Lab <span className="text-slate-300 font-light mx-2">/</span> Master Database
          </h2>
          <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mt-1">Unified Technical Specifications Repository</p>
        </div>

        <div className="flex items-center gap-3">
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setView('library')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'library' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid2X2 size={18}/> Library</button>
            <button onClick={() => setView('comparison')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'comparison' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Split size={18}/> Compare</button>
          </div>
          <button onClick={handleOpenCreate} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black shadow-xl shadow-indigo-200 flex items-center gap-2 hover:bg-indigo-700 active:scale-95 transition-all">
            <Plus size={20}/> Add Master Style
          </button>
        </div>
      </div>

      {/* SEARCH BAR */}
      <div className="relative max-w-xl">
        <input 
          type="text" 
          placeholder="Search by Style No or Category..." 
          className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-300 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-lg font-medium shadow-sm transition-all bg-white text-slate-900"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <Search className="absolute left-4 top-4.5 text-slate-400" size={24}/>
      </div>

      {/* VIEW: LIBRARY */}
      {view === 'library' && (
        <div className="space-y-4 animate-fade-in">
          {loading ? (
            <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest flex flex-col items-center gap-4">
              <Loader2 className="animate-spin text-indigo-600" size={48}/>
              Scanning Library...
            </div>
          ) : filteredStyles.length === 0 ? (
            <div className="p-20 bg-white rounded-3xl border border-slate-200 text-center">
              <AlertCircle size={64} className="mx-auto text-slate-200 mb-4"/>
              <p className="text-xl font-black text-slate-400">No Master Styles Found.</p>
            </div>
          ) : (
            filteredStyles.map(style => {
              const isExpanded = expandedStyles.includes(style.id);
              return (
                <div key={style.id} className={`bg-white rounded-3xl border shadow-sm transition-all overflow-hidden ${isExpanded ? 'border-indigo-400 shadow-xl ring-4 ring-indigo-500/5' : 'border-slate-200 hover:border-indigo-300'}`}>
                  {/* Summary Header */}
                  <div className={`p-6 flex items-center justify-between cursor-pointer transition-colors ${isExpanded ? 'bg-indigo-50' : 'hover:bg-slate-50'}`} onClick={() => toggleExpand(style.id)}>
                    <div className="flex items-center gap-6">
                      <div className="w-16 h-16 bg-white rounded-2xl border-2 border-indigo-100 flex items-center justify-center font-black text-indigo-600 text-xl shadow-inner">
                        {style.style_no.slice(0,2).toUpperCase()}
                      </div>
                      <div>
                        <h3 className="text-2xl font-black text-slate-800">{style.style_no}</h3>
                        <div className="flex items-center gap-3 mt-1">
                          <span className="text-[10px] font-black uppercase tracking-widest bg-indigo-100 text-indigo-700 px-2.5 py-1 rounded-md">{style.category}</span>
                          <span className="text-xs font-bold text-slate-400 tracking-tight">Packing: {style.packing_type} &bull; {style.pcs_per_box} pcs/box</span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center gap-4">
                      <button onClick={(e) => { e.stopPropagation(); handlePrintStyle(style); }} className="p-3 bg-white text-slate-400 hover:text-indigo-600 rounded-xl border border-slate-200 hover:border-indigo-200 transition-all shadow-sm"><Printer size={20}/></button>
                      <button onClick={(e) => { e.stopPropagation(); handleEdit(style); }} className="p-3 bg-white text-slate-400 hover:text-blue-600 rounded-xl border border-slate-200 hover:border-blue-200 transition-all shadow-sm"><ImageIcon size={20}/></button>
                      <button onClick={(e) => { e.stopPropagation(); handleDelete(style.id); }} className="p-3 bg-white text-slate-400 hover:text-red-600 rounded-xl border border-slate-200 hover:border-red-200 transition-all shadow-sm"><Trash2 size={20}/></button>
                      <div className={`p-2 rounded-full transition-transform duration-300 ${isExpanded ? 'rotate-180 bg-indigo-600 text-white' : 'text-slate-300'}`}>
                        <ChevronDown size={24}/>
                      </div>
                    </div>
                  </div>

                  {/* Expanded Content */}
                  {isExpanded && (
                    <div className="p-8 bg-white border-t border-indigo-100 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 animate-fade-in">
                      {SECTIONS.map(section => {
                        const sectionDetails = style.details?.filter(d => d.section === section) || [];
                        return (
                          <div key={section} className="space-y-4">
                            <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 border-b border-slate-100 pb-2">{section}</h4>
                            <div className="space-y-6">
                              {sectionDetails.map(d => (
                                <div key={d.label}>
                                  <div className="text-xs font-black text-indigo-600 uppercase tracking-tight mb-1">{d.label}</div>
                                  <div className="text-sm font-medium text-slate-600 leading-relaxed whitespace-pre-wrap">{d.content_text || '---'}</div>
                                  {d.attachments.length > 0 && (
                                    <div className="flex gap-2 mt-3 flex-wrap">
                                      {d.attachments.map((a, i) => (
                                        <a key={i} href={a.url} target="_blank" rel="noreferrer" className="w-10 h-10 rounded-lg border border-slate-200 bg-slate-50 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:border-indigo-200 transition-all" title={a.name}>
                                          {a.type === 'image' ? <ImageIcon size={14}/> : <FileText size={14}/>}
                                        </a>
                                      ))}
                                    </div>
                                  )}
                                </div>
                              ))}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })
          )}
        </div>
      )}

      {/* VIEW: COMPARISON */}
      {view === 'comparison' && (
        <div className="flex gap-6 animate-fade-in overflow-x-auto pb-10 min-h-[600px] items-start scrollbar-hide">
          {/* SEARCH & ADD SIDEBAR */}
          <div className="w-80 shrink-0 bg-white rounded-3xl border border-slate-200 p-6 space-y-4 sticky left-0 shadow-xl shadow-slate-200/50">
             <h3 className="font-black text-slate-700 uppercase tracking-widest text-xs flex items-center gap-2">
                <Search size={14}/> Add Styles to Compare
             </h3>
             <div className="space-y-2">
                {styles.map(s => {
                  const isSelected = selectedForCompare.includes(s.id);
                  return (
                    <button 
                      key={s.id} 
                      onClick={() => setSelectedForCompare(prev => isSelected ? prev.filter(i => i !== s.id) : [...prev, s.id])}
                      className={`w-full p-4 rounded-2xl border-2 text-left transition-all flex items-center justify-between group ${isSelected ? 'border-indigo-600 bg-indigo-50 shadow-md' : 'border-slate-50 hover:border-indigo-200 bg-slate-50'}`}
                    >
                      <div>
                        <div className={`font-black text-lg ${isSelected ? 'text-indigo-900' : 'text-slate-700'}`}>{s.style_no}</div>
                        <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{s.category}</div>
                      </div>
                      <div className={`p-1.5 rounded-full transition-all ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-200 text-slate-400 group-hover:bg-indigo-100 group-hover:text-indigo-600'}`}>
                        {isSelected ? <X size={14}/> : <Plus size={14}/>}
                      </div>
                    </button>
                  );
                })}
             </div>
             {selectedForCompare.length === 0 && (
               <div className="py-20 text-center text-slate-300 italic text-sm">
                  Search and pick styles to see them side-by-side.
               </div>
             )}
          </div>

          {/* COMPARISON SLOTS */}
          <div className="flex gap-6">
            {selectedForCompare.map(styleId => {
              const style = styles.find(s => s.id === styleId);
              if (!style) return null;
              return (
                <div key={style.id} className="w-[450px] shrink-0 bg-white rounded-3xl border-2 border-indigo-100 shadow-2xl overflow-hidden flex flex-col max-h-[85vh] animate-scale-up">
                   <div className="p-6 bg-indigo-600 text-white flex justify-between items-start">
                      <div>
                        <h4 className="text-3xl font-black tracking-tight">{style.style_no}</h4>
                        <div className="text-[10px] font-black uppercase bg-white/20 px-2 py-1 rounded mt-1 inline-block">{style.category}</div>
                      </div>
                      <button onClick={() => setSelectedForCompare(prev => prev.filter(i => i !== style.id))} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24}/></button>
                   </div>
                   <div className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/30">
                      {SECTIONS.map(section => {
                         const sectionDetails = style.details?.filter(d => d.section === section) || [];
                         return (
                           <div key={section} className="space-y-4">
                              <h5 className="font-black text-indigo-400 text-[10px] uppercase tracking-widest border-b border-indigo-100 pb-2">{section}</h5>
                              <div className="space-y-4">
                                {sectionDetails.map(d => (
                                  <div key={d.label} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                                     <div className="text-xs font-black text-slate-800 uppercase tracking-tight mb-2 flex items-center justify-between">
                                        {d.label}
                                        {d.attachments.length > 0 && <span className="bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded text-[9px] uppercase font-black">{d.attachments.length} files</span>}
                                     </div>
                                     <div className="text-sm font-medium text-slate-600 leading-relaxed whitespace-pre-wrap">{d.content_text || '---'}</div>

                                     {d.attachments.length > 0 && (
                                       <div className="grid grid-cols-2 gap-2 mt-4">
                                          {d.attachments.map((a, i) => (
                                            <a key={i} href={a.url} target="_blank" rel="noreferrer" className="block rounded-xl border border-slate-100 overflow-hidden hover:shadow-lg transition-all group relative">
                                               {a.type === 'image' ? (
                                                  <img src={a.url} className="w-full h-32 object-cover transition-transform group-hover:scale-110"/>
                                               ) : (
                                                  <div className="w-full h-32 bg-slate-50 flex flex-col items-center justify-center text-slate-400 gap-2">
                                                     <FileText size={32}/>
                                                     <span className="text-[10px] px-2 text-center truncate w-full font-bold">{a.name}</span>
                                                  </div>
                                               )}
                                               <div className="absolute inset-0 bg-indigo-600/60 opacity-0 group-hover:opacity-100 flex items-center justify-center text-white transition-opacity">
                                                  <Download size={20}/>
                                               </div>
                                            </a>
                                          ))}
                                       </div>
                                     )}
                                  </div>
                                ))}
                              </div>
                           </div>
                         );
                      })}
                   </div>
                   <div className="p-4 border-t bg-slate-50 flex justify-between">
                      <button onClick={() => handlePrintStyle(style)} className="flex-1 flex items-center justify-center gap-2 font-black text-xs text-indigo-600 uppercase tracking-widest hover:bg-white py-3 rounded-xl transition-all"><Printer size={16}/> Full Print</button>
                      <button onClick={() => handleEdit(style)} className="flex-1 flex items-center justify-center gap-2 font-black text-xs text-blue-600 uppercase tracking-widest hover:bg-white py-3 rounded-xl transition-all"><ImageIcon size={16}/> Quick Edit</button>
                   </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* MASTER EDITOR MODAL */}
      {isEditorOpen && editingStyle && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
            <div className="p-8 border-b bg-slate-50 flex justify-between items-center">
              <div>
                <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingStyle.id ? 'Edit Master Style' : 'New Master Library Record'}</h3>
                <p className="text-slate-400 text-xs font-black uppercase tracking-widest mt-1">Populating technical manufacturing standards</p>
              </div>
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => setIsCopying(!isCopying)} 
                  className="bg-indigo-50 text-indigo-600 border border-indigo-200 px-6 py-3 rounded-2xl text-sm font-black flex items-center gap-2 hover:bg-indigo-100 transition-all"
                >
                  <Copy size={20}/> {isCopying ? 'Cancel Cloning' : 'Copy From Style'}
                </button>
                <button onClick={() => setIsEditorOpen(false)} className="text-slate-300 hover:text-slate-600 transition-colors p-2 hover:bg-slate-100 rounded-full"><X size={40}/></button>
              </div>
            </div>

            <div className="flex-1 flex overflow-hidden">
               {/* SIDEBAR: CLONE SELECTOR */}
               {isCopying && (
                 <div className="w-80 border-r border-slate-200 bg-slate-50 p-6 overflow-y-auto animate-fade-in shrink-0">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6">Select Source Material</h4>
                    <div className="space-y-3">
                       {styles.map(s => (
                         <button key={s.id} onClick={() => handleCopyFrom(s)} className="w-full text-left p-4 bg-white rounded-2xl border border-slate-200 hover:border-indigo-500 hover:shadow-lg transition-all group">
                            <div className="font-black text-lg text-slate-700 group-hover:text-indigo-600">{s.style_no}</div>
                            <div className="text-[10px] font-bold text-slate-400">{s.category} Master</div>
                         </button>
                       ))}
                    </div>
                 </div>
               )}

               <div className="flex-1 overflow-y-auto p-10 space-y-12">
                  {/* General Fields */}
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
                    <div className="col-span-2">
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Style Reference No.</label>
                       <input 
                         className="w-full border-2 border-slate-100 rounded-2xl p-5 bg-white text-slate-900 text-2xl font-black focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm"
                         placeholder="e.g. ST-2024-X"
                         value={editingStyle.style_no}
                         onChange={e => setEditingStyle({...editingStyle, style_no: e.target.value})}
                       />
                    </div>
                    <div>
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Product Category</label>
                       <select 
                         className="w-full border-2 border-slate-100 rounded-2xl p-5 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none appearance-none shadow-sm"
                         value={editingStyle.category}
                         onChange={e => setEditingStyle({...editingStyle, category: e.target.value as any})}
                       >
                         <option value="Casuals">Casuals</option>
                         <option value="Lite">Lite</option>
                         <option value="Sportz">Sportz</option>
                       </select>
                    </div>
                    <div>
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Packing Configuration</label>
                       <input 
                         className="w-full border-2 border-slate-100 rounded-2xl p-5 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm"
                         placeholder="e.g. Pouch, Box"
                         value={editingStyle.packing_type}
                         onChange={e => setEditingStyle({...editingStyle, packing_type: e.target.value})}
                       />
                    </div>
                  </div>

                  {/* Requirements Matrix */}
                  <div className="space-y-16">
                    {SECTIONS.map(section => {
                       const sectionDetails = details.filter(d => d.section === section);
                       return (
                         <div key={section} className="space-y-6">
                            <div className="flex justify-between items-center border-b-2 border-slate-100 pb-3">
                              <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">{section}</h4>
                              <button onClick={() => addCustomTopic(section)} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-600 hover:text-white transition-all">
                                + Add Custom Field
                              </button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                               {details.map((d, idx) => {
                                 if (d.section !== section) return null;
                                 return (
                                   <div key={idx} className="group bg-slate-50/50 p-6 rounded-3xl border border-transparent hover:border-indigo-100 hover:bg-white transition-all space-y-4">
                                      <div className="flex justify-between items-center">
                                         <input 
                                           className="bg-transparent border-none p-0 text-xs font-black text-indigo-600 uppercase tracking-widest focus:ring-0 w-2/3"
                                           value={d.label}
                                           onChange={e => {
                                             const updated = [...details];
                                             updated[idx].label = e.target.value;
                                             setDetails(updated);
                                           }}
                                         />
                                         <button onClick={() => removeDetail(idx)} className="p-2 text-slate-200 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><X size={16}/></button>
