                                      <textarea 
                                        className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm h-32 bg-white text-slate-800 font-medium focus:border-indigo-400 outline-none transition-all resize-none shadow-inner"
                                        placeholder={`Technical details for ${d.label}...`}
                                        value={d.content_text}
                                        onChange={e => {
                                          const updated = [...details];
                                          updated[idx].content_text = e.target.value;
                                          setDetails(updated);
                                        }}
                                      />

