                          );
                        })}
                      </tbody>
                    </table>
                  )}
                </div>
              );
            })
          )}
        </div>
        <div className="p-4 bg-slate-50 text-right border-t">
          <button onClick={onClose} className="bg-slate-800 text-white px-4 py-2 rounded font-medium hover:bg-slate-700">Close</button>
        </div>
