  );
};

import React, { useEffect, useState } from 'react';
import { fetchStyleLibrary, upsertStyle, deleteStyle, uploadOrderAttachment } from '../services/db';
import { StyleLibrary, StyleDetail, Attachment } from '../types';
import { 
  Library, 
  Search, 
  Plus, 
  Trash2, 
  Copy, 
  Printer, 
  ChevronDown, 
  ChevronRight, 
  X, 
  Upload, 
  FileText, 
  Image as ImageIcon, 
  Save, 
  Loader2, 
  Compare, 
  Split, 
  Grid2X2,
  AlertCircle,
  Download,
  MoreVertical
} from 'lucide-react';

const SECTIONS = [
  'General Info',
  'Pre Production Requirements & INFO',
  'Requirements during production',
  'Packing Requirements'
];

const DEFAULT_TOPICS: Record<string, string[]> = {
  'General Info': ['Style Text', 'Category', 'Type of packing', 'no of pieces / box'],
  'Pre Production Requirements & INFO': ['Fabric', 'Colours & size', 'Measurement chart'],
  'Requirements during production': ['Elastic', 'Fusing sticker', 'Cone', 'Rope', 'Zipper', 'Stiching info'],
  'Packing Requirements': ['Photo tag', 'Tag', 'Feature tag', 'Hook', 'Loop', 'Inner board', 'Plastic cover/ pouch', 'Size sticker', 'Box']
};

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<StyleLibrary[]>([]);
  const [view, setView] = useState<'library' | 'comparison'>('library');
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [expandedStyles, setExpandedStyles] = useState<string[]>([]);
  const [selectedForCompare, setSelectedForCompare] = useState<string[]>([]);

  // Modal / Editor State
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [editingStyle, setEditingStyle] = useState<Partial<StyleLibrary> | null>(null);
  const [details, setDetails] = useState<StyleDetail[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopying, setIsCopying] = useState(false);

  const loadData = async () => {
    setLoading(true);
    const data = await fetchStyleLibrary();
    setStyles(data);
    setLoading(false);
  };

  useEffect(() => { loadData(); }, []);

  const toggleExpand = (id: string) => {
    setExpandedStyles(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleOpenCreate = () => {
    setEditingStyle({ style_no: '', category: 'Casuals', pcs_per_box: 1, packing_type: 'cover' });
    const initialDetails: StyleDetail[] = [];
    SECTIONS.forEach(section => {
      DEFAULT_TOPICS[section].forEach(label => {
        initialDetails.push({ section, label, content_text: '', attachments: [] });
      });
    });
    setDetails(initialDetails);
    setIsEditorOpen(true);
  };

  const handleEdit = (style: StyleLibrary) => {
    setEditingStyle(style);
    setDetails(style.details || []);
    setIsEditorOpen(true);
  };

  const handleCopyFrom = (sourceStyle: StyleLibrary) => {
    if (!editingStyle) return;
    const copiedDetails = sourceStyle.details?.map(d => ({
      ...d,
      id: undefined,
      style_id: undefined
    })) || [];
    setDetails(copiedDetails);
    setIsCopying(false);
  };

  const addCustomTopic = (section: string) => {
    setDetails([...details, { section, label: 'New Topic', content_text: '', attachments: [] }]);
  };

  const removeDetail = (index: number) => {
    setDetails(details.filter((_, i) => i !== index));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, detailIndex: number) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const updated = [...details];
    /* Explicitly cast Array.from(files) to File[] to fix type inference issues where file was seen as unknown */
    for (const file of Array.from(files) as File[]) {
      const url = await uploadOrderAttachment(file);
      if (url) {
        updated[detailIndex].attachments.push({
          name: file.name,
          url,
          type: (file.type.startsWith('image/') ? 'image' : 'document') as 'image' | 'document'
        });
      }
    }
    setDetails(updated);
  };

  const handleSave = async () => {
    if (!editingStyle?.style_no) return alert("Style Number is required");
    setIsSubmitting(true);
    const result = await upsertStyle(editingStyle, details);
    if (result.error) alert(result.error);
    else {
      setIsEditorOpen(false);
      loadData();
    }
    setIsSubmitting(false);
  };

  const handleDelete = async (id: string) => {
    if (confirm("Delete this style master?")) {
      await deleteStyle(id);
      loadData();
    }
  };

  const handlePrintStyle = (style: StyleLibrary) => {
    const win = window.open('', 'PrintStyle', 'width=1000,height=800');
    if (!win) return;

    const sectionsHtml = SECTIONS.map(section => {
      const sectionDetails = style.details?.filter(d => d.section === section) || [];
      if (sectionDetails.length === 0) return '';

      return `
        <div class="print-section">
          <h2 class="section-title">${section}</h2>
          <div class="details-grid">
            ${sectionDetails.map(d => `
              <div class="detail-box">
                <div class="detail-label">${d.label}</div>
                <div class="detail-content">${d.content_text || '---'}</div>
                ${d.attachments.length > 0 ? `
                  <div class="attachment-gallery">
                    ${d.attachments.map(a => a.type === 'image' 
                      ? `<div class="img-container"><img src="${a.url}" /><div class="img-name">${a.name}</div></div>`
                      : `<div class="doc-link">📄 ${a.name}</div>`
                    ).join('')}
                  </div>
                ` : ''}
              </div>
            `).join('')}
          </div>
        </div>
      `;
    }).join('');

    win.document.write(`
      <html><head><title>Style Report - ${style.style_no}</title>
      <style>
        @media print { body { -webkit-print-color-adjust: exact; } }
        body { font-family: system-ui, sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; }
        .header { border-bottom: 4px solid #1e293b; padding-bottom: 20px; margin-bottom: 30px; display: flex; justify-content: space-between; align-items: flex-end; }
        .style-no { font-size: 42px; font-weight: 900; margin: 0; color: #4f46e5; }
        .category { font-size: 18px; font-weight: bold; color: #64748b; text-transform: uppercase; }
        .section-title { background: #f1f5f9; padding: 10px 15px; border-left: 5px solid #4f46e5; margin: 40px 0 20px 0; font-size: 20px; font-weight: 800; text-transform: uppercase; }
        .detail-box { margin-bottom: 25px; border: 1px solid #e2e8f0; padding: 20px; border-radius: 8px; page-break-inside: avoid; }
        .detail-label { font-weight: 900; font-size: 14px; text-transform: uppercase; color: #475569; border-bottom: 1px solid #f1f5f9; padding-bottom: 5px; margin-bottom: 10px; }
        .detail-content { font-size: 16px; color: #0f172a; white-space: pre-wrap; }
        .attachment-gallery { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-top: 15px; }
        .img-container { border: 1px solid #ddd; padding: 5px; border-radius: 4px; text-align: center; }
        .img-container img { max-width: 100%; max-height: 400px; border-radius: 2px; }
        .img-name { font-size: 10px; color: #94a3b8; margin-top: 5px; }
        .doc-link { background: #f8fafc; padding: 8px; border-radius: 4px; font-size: 12px; font-weight: bold; border: 1px solid #e2e8f0; }
      </style>
      </head><body>
        <div class="header">
          <div><h1 class="style-no">STYLE: ${style.style_no}</h1><div class="category">${style.category} Master Library</div></div>
          <div style="text-align: right; font-size: 12px; color: #64748b;">Printed on: ${new Date().toLocaleString()}</div>
        </div>
        ${sectionsHtml}
      </body></html>
    `);
    win.document.close();
    setTimeout(() => { win.print(); }, 1000);
  };

  const filteredStyles = styles.filter(s => 
    s.style_no.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg">
              <Library size={28}/> 
            </div>
            Style Lab <span className="text-slate-300 font-light mx-2">/</span> Master Database
          </h2>
          <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mt-1">Unified Technical Specifications Repository</p>
        </div>

        <div className="flex items-center gap-3">
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setView('library')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'library' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid2X2 size={18}/> Library</button>
            <button onClick={() => setView('comparison')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'comparison' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Split size={18}/> Compare</button>
          </div>
          <button onClick={handleOpenCreate} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black shadow-xl shadow-indigo-200 flex items-center gap-2 hover:bg-indigo-700 active:scale-95 transition-all">
            <Plus size={20}/> Add Master Style
          </button>
        </div>
      </div>

      {/* SEARCH BAR */}
      <div className="relative max-w-xl">
        <input 
          type="text" 
          placeholder="Search by Style No or Category..." 
          className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-300 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-lg font-medium shadow-sm transition-all bg-white text-slate-900"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <Search className="absolute left-4 top-4.5 text-slate-400" size={24}/>
      </div>

      {/* VIEW: LIBRARY */}
      {view === 'library' && (
        <div className="space-y-4 animate-fade-in">
          {loading ? (
            <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest flex flex-col items-center gap-4">
              <Loader2 className="animate-spin text-indigo-600" size={48}/>
              Scanning Library...
            </div>
          ) : filteredStyles.length === 0 ? (
            <div className="p-20 bg-white rounded-3xl border border-slate-200 text-center">
              <AlertCircle size={64} className="mx-auto text-slate-200 mb-4"/>
              <p className="text-xl font-black text-slate-400">No Master Styles Found.</p>
            </div>
          ) : (
            filteredStyles.map(style => {
              const isExpanded = expandedStyles.includes(style.id);
              return (
                <div key={style.id} className={`bg-white rounded-3xl border shadow-sm transition-all overflow-hidden ${isExpanded ? 'border-indigo-400 shadow-xl ring-4 ring-indigo-500/5' : 'border-slate-200 hover:border-indigo-300'}`}>
                  {/* Summary Header */}
