                    <div className="flex items-center gap-6">
                      <div className="w-16 h-16 bg-white rounded-2xl border-2 border-indigo-100 flex items-center justify-center font-black text-indigo-600 text-xl shadow-inner">
                        {style.style_no.slice(0,2).toUpperCase()}
                      </div>
                      <div>
                        <h3 className="text-2xl font-black text-slate-800">{style.style_no}</h3>
                        <div className="flex items-center gap-3 mt-1">
                          <span className="text-[10px] font-black uppercase tracking-widest bg-indigo-100 text-indigo-700 px-2.5 py-1 rounded-md">{style.category}</span>
                          <span className="text-xs font-bold text-slate-400 tracking-tight">Packing: {style.packing_type} &bull; {style.pcs_per_box} pcs/box</span>
