                    <div className="col-span-2">
                       <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Style Reference No.</label>
                       <input 
                         className="w-full border-2 border-slate-100 rounded-2xl p-5 bg-white text-slate-900 text-2xl font-black focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm"
