                       />
                    </div>
                  </div>

                  {/* Requirements Matrix */}
                  <div className="space-y-16">
                    {SECTIONS.map(section => {
                       const sectionDetails = details.filter(d => d.section === section);
                       return (
                         <div key={section} className="space-y-6">
                            <div className="flex justify-between items-center border-b-2 border-slate-100 pb-3">
                              <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">{section}</h4>
                              <button onClick={() => addCustomTopic(section)} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-600 hover:text-white transition-all">
                                + Add Custom Field
                              </button>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                               {details.map((d, idx) => {
