                                            <label className="w-16 h-16 rounded-xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-300 hover:border-indigo-400 hover:text-indigo-400 cursor-pointer transition-all">
                                               <Upload size={16}/>
                                               <input type="file" multiple className="hidden" onChange={e => handleFileUpload(e, idx)}/>
                                            </label>
                                         </div>
                                      </div>
                                   </div>
                                 );
                               })}
                            </div>
                         </div>
                       );
                    })}
                  </div>
               </div>
            </div>

            <div className="p-8 border-t bg-slate-50 flex justify-end gap-4 shadow-[0_-10px_20px_rgba(0,0,0,0.03)]">
               <button 
                onClick={() => setIsEditorOpen(false)} 
                className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 hover:bg-white rounded-2xl transition-all uppercase tracking-widest text-xs"
               >
                Discard
               </button>
               <button 
                onClick={handleSave} 
                disabled={isSubmitting}
                className="px-16 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs"
               >
                 {isSubmitting ? <><Loader2 size={20} className="animate-spin"/> Syncing...</> : <><Save size={20}/> Save Master Style</>}
               </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

