export const uploadOrderAttachment = async (file: File): Promise<string | null> => {
    const fileExt = file.name.split('.').pop();
    const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
    const { error } = await supabase.storage.from('order-attachments').upload(fileName, file);
    if (error) return null;
    const { data } = supabase.storage.from('order-attachments').getPublicUrl(fileName);
    return data.publicUrl;
};

import React, { useEffect, useState } from 'react';
import { fetchStyleLibrary, upsertStyle, deleteStyle, uploadOrderAttachment } from '../services/db';
import { StyleLibrary, StyleDetail, Attachment } from '../types';
import { 
  Library, 
  Search, 
  Plus, 
  Trash2, 
  Copy, 
  Printer, 
  ChevronDown, 
  ChevronRight, 
  X, 
  Upload, 
  FileText, 
  Image as ImageIcon, 
  Save, 
  Loader2, 
  Split, 
  Grid2X2,
  AlertCircle,
  Download,
  MoreVertical,
  Layers,
  Users
} from 'lucide-react';

const SECTIONS = [
  'General Info',
  'Pre Production Requirements & INFO',
  'Requirements during production',
  'Packing Requirements'
];

const DEFAULT_TOPICS: Record<string, string[]> = {
  'General Info': ['Style Text', 'Category', 'Type of packing', 'no of pieces / box'],
  'Pre Production Requirements & INFO': ['Fabric', 'Colours & size', 'Measurement chart'],
  'Requirements during production': ['Elastic', 'Fusing sticker', 'Cone', 'Rope', 'Zipper', 'Stiching info'],
  'Packing Requirements': ['Photo tag', 'Tag', 'Feature tag', 'Hook', 'Loop', 'Inner board', 'Plastic cover/ pouch', 'Size sticker', 'Box']
};

const COMMON_PRODUCT_TYPES = ['T-shirt', 'Pant', 'Shorts', 'Shirt', 'Innerwear', 'Sweatshirt', 'Hoodie'];

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<StyleLibrary[]>([]);
  const [view, setView] = useState<'library' | 'comparison'>('library');
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [expandedStyles, setExpandedStyles] = useState<string[]>([]);
  const [selectedForCompare, setSelectedForCompare] = useState<string[]>([]);

  // Modal / Editor State
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [editingStyle, setEditingStyle] = useState<Partial<StyleLibrary> | null>(null);
  const [details, setDetails] = useState<StyleDetail[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopying, setIsCopying] = useState(false);

  // Custom Product Type handling
  const [showNewTypeInput, setShowNewTypeInput] = useState(false);
  const [customProductType, setCustomProductType] = useState('');

  const loadData = async () => {
    setLoading(true);
    const data = await fetchStyleLibrary();
    setStyles(data);
    setLoading(false);
  };

  useEffect(() => { loadData(); }, []);

  const toggleExpand = (id: string) => {
    setExpandedStyles(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleOpenCreate = () => {
    setEditingStyle({ 
        style_no: '', 
        style_text: '',
        category: 'Casuals', 
        product_type: 'T-shirt',
        target_audience: 'Men',
        pcs_per_box: 1, 
        packing_type: 'cover' 
    });
    const initialDetails: StyleDetail[] = [];
    SECTIONS.forEach(section => {
      DEFAULT_TOPICS[section].forEach(label => {
        initialDetails.push({ section, label, content_text: '', attachments: [] });
      });
    });
    setDetails(initialDetails);
    setIsEditorOpen(true);
    setShowNewTypeInput(false);
  };

  const handleEdit = (style: StyleLibrary) => {
    setEditingStyle(style);
    setDetails(style.details || []);
    setIsEditorOpen(true);
    setShowNewTypeInput(!COMMON_PRODUCT_TYPES.includes(style.product_type));
  };

  const handleCopyFrom = (sourceStyle: StyleLibrary) => {
    if (!editingStyle) return;
    const copiedDetails = sourceStyle.details?.map(d => ({
      ...d,
      id: undefined,
      style_id: undefined
    })) || [];
    setDetails(copiedDetails);
    setIsCopying(false);
  };

  const addCustomTopic = (section: string) => {
    setDetails([...details, { section, label: 'New Topic', content_text: '', attachments: [] }]);
  };

  const removeDetail = (index: number) => {
    setDetails(details.filter((_, i) => i !== index));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, detailIndex: number) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    const updated = [...details];
    for (const file of Array.from(files) as File[]) {
      const url = await uploadOrderAttachment(file);
      if (url) {
        updated[detailIndex].attachments.push({
          name: file.name,
          url,
          type: (file.type.startsWith('image/') ? 'image' : 'document') as 'image' | 'document'
        });
      }
    }
    setDetails(updated);
  };

  const handleSave = async () => {
    if (!editingStyle?.style_no) return alert("Style Number is required");
    setIsSubmitting(true);

    const finalStyle = {
        ...editingStyle,
        product_type: showNewTypeInput ? customProductType : editingStyle.product_type
    };

    const result = await upsertStyle(finalStyle, details);
    if (result.error) alert(result.error);
    else {
      setIsEditorOpen(false);
      loadData();
    }
    setIsSubmitting(false);
  };

  const handleDelete = async (id: string) => {
    if (confirm("Delete this style master?")) {
