  const handlePrintStyle = (style: StyleLibrary) => {
    const win = window.open('', 'PrintStyle', 'width=1000,height=800');
    if (!win) return;

    const sectionsHtml = SECTIONS.map(section => {
      const sectionDetails = style.details?.filter(d => d.section === section) || [];
