      <html><head><title>Style Report - ${style.style_no}</title>
      <style>
        @media print { body { -webkit-print-color-adjust: exact; } }
        body { font-family: system-ui, sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; }
        .header { border-bottom: 4px solid #1e293b; padding-bottom: 20px; margin-bottom: 30px; display: flex; justify-content: space-between; align-items: flex-end; }
        .style-no { font-size: 32px; font-weight: 900; margin: 0; color: #4f46e5; line-height: 1; }
        .style-text { font-size: 16px; font-weight: 600; color: #64748b; margin-top: 4px; }
        .meta-badges { display: flex; gap: 8px; margin-top: 10px; }
        .badge { background: #f1f5f9; padding: 4px 10px; border-radius: 4px; font-size: 11px; font-weight: 800; text-transform: uppercase; color: #475569; border: 1px solid #e2e8f0; }
        .section-title { background: #f1f5f9; padding: 10px 15px; border-left: 5px solid #4f46e5; margin: 40px 0 20px 0; font-size: 20px; font-weight: 800; text-transform: uppercase; }
        .detail-box { margin-bottom: 25px; border: 1px solid #e2e8f0; padding: 20px; border-radius: 8px; page-break-inside: avoid; }
        .detail-label { font-weight: 900; font-size: 14px; text-transform: uppercase; color: #475569; border-bottom: 1px solid #f1f5f9; padding-bottom: 5px; margin-bottom: 10px; }
        .detail-content { font-size: 16px; color: #0f172a; white-space: pre-wrap; }
        .attachment-gallery { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-top: 15px; }
        .img-container { border: 1px solid #ddd; padding: 5px; border-radius: 4px; text-align: center; }
        .img-container img { max-width: 100%; max-height: 400px; border-radius: 2px; }
        .img-name { font-size: 10px; color: #94a3b8; margin-top: 5px; }
        .doc-link { background: #f8fafc; padding: 8px; border-radius: 4px; font-size: 12px; font-weight: bold; border: 1px solid #e2e8f0; }
      </style>
      </head><body>
        <div class="header">
          <div>
            <h1 class="style-no">STYLE: ${style.style_no}</h1>
            <div class="style-text">${style.style_text || ''}</div>
            <div class="meta-badges">
