          <div className="flex gap-6">
            {selectedForCompare.map(styleId => {
              const style = styles.find(s => s.id === styleId);
              if (!style) return null;
              return (
                <div key={style.id} className="w-[450px] shrink-0 bg-white rounded-3xl border-2 border-indigo-100 shadow-2xl overflow-hidden flex flex-col max-h-[85vh] animate-scale-up">
                   <div className="p-6 bg-indigo-600 text-white flex justify-between items-start">
                      <div>
                        <h4 className="text-3xl font-black tracking-tight">{style.style_no}</h4>
                        <div className="flex gap-2 mt-1">
                            <div className="text-[9px] font-black uppercase bg-white/20 px-2 py-1 rounded inline-block">{style.category}</div>
                            <div className="text-[9px] font-black uppercase bg-white/20 px-2 py-1 rounded inline-block">{style.product_type}</div>
                            <div className="text-[9px] font-black uppercase bg-white px-2 py-1 rounded inline-block text-indigo-700">{style.target_audience}</div>
                        </div>
                      </div>
                      <button onClick={() => setSelectedForCompare(prev => prev.filter(i => i !== style.id))} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={24}/></button>
