                                     <div className="text-xs font-black text-slate-800 uppercase tracking-tight mb-2 flex items-center justify-between">
                                        {d.label}
                                        {d.attachments.length > 0 && <span className="bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded text-[9px] uppercase font-black">{d.attachments.length} files</span>}
