export const getNextOrderStatus = (current: OrderStatus): OrderStatus | null => {
  switch (current) {
    case OrderStatus.ASSIGNED: return OrderStatus.IN_PROGRESS;
    case OrderStatus.IN_PROGRESS: return OrderStatus.QC;
    case OrderStatus.QC: return OrderStatus.QC_APPROVED;
    case OrderStatus.QC_APPROVED: return OrderStatus.COMPLETED; 
    case OrderStatus.PACKED: return OrderStatus.COMPLETED;
    default: return null;
  }
};

export const getNextBarcodeStatus = (current: BarcodeStatus): BarcodeStatus | null => {
  switch (current) {
    case BarcodeStatus.GENERATED: return BarcodeStatus.DETAILS_FILLED;
    case BarcodeStatus.DETAILS_FILLED: return BarcodeStatus.PUSHED_OUT_OF_SUBUNIT;
    case BarcodeStatus.PUSHED_OUT_OF_SUBUNIT: return BarcodeStatus.QC_APPROVED;
    case BarcodeStatus.QC_APPROVED: return BarcodeStatus.COMMITTED_TO_STOCK;
    case BarcodeStatus.COMMITTED_TO_STOCK: return BarcodeStatus.SOLD;
    default: return null;
  }
};

export const formatOrderNumber = (order: Partial<Order>): string => {
  if (!order.order_no) return 'ORD-NEW';
  const numericMatch = order.order_no.match(/ORD-(\d+)/);
  const serial = numericMatch ? numericMatch[1] : order.order_no;
  const stylePart = order.style_number 
    ? order.style_number.split('-')[0].trim() 
    : 'STYLE';
  return `ORD-${stylePart}-${serial}`;
};

import { supabase } from './supabase';
import { Order, OrderStatus, MaterialRequest, Barcode, BarcodeStatus, Unit, MaterialStatus, Invoice, SizeBreakdown, AppUser, UserRole, StockCommit, MaterialApproval, OrderLog, Attachment, StyleLibrary, StyleDetail, StyleTemplate } from '../types';

const API_BASE = (typeof window !== 'undefined' && (window.location.protocol === 'file:' || window.location.hostname === 'localhost'))
  ? 'https://tintura-mail.vercel.app'
  : '';

// --- STYLE TEMPLATE API ---

export const fetchStyleTemplate = async (): Promise<StyleTemplate[]> => {
    const { data, error } = await supabase
        .from('style_template')
        .select('*')
        .order('display_order');
    if (error) return [];
    return data || [];
};

export const saveStyleTemplate = async (template: StyleTemplate[]): Promise<void> => {
    // 1. Delete removed sections if any (not strictly required if UPSERT used, but cleaner)
    // 2. Upsert current template
    const { error } = await supabase
        .from('style_template')
        .upsert(template.map((t, i) => ({
            section: t.section,
            labels: t.labels,
            display_order: i + 1
        })));
    if (error) throw error;
};

export const checkTemplateDeletionImpact = async (section: string, labels: string[]): Promise<string[]> => {
    // Check if any style has data for labels that are about to be removed
    const { data, error } = await supabase
        .from('style_details')
        .select('label, style_library(style_no)')
        .eq('section', section)
        .not('label', 'in', `(${labels.map(l => `"${l}"`).join(',')})`)
        .or('content_text.neq."",attachments.neq.[]::jsonb');

    if (error || !data) return [];

    // Return unique labels that have data
    const impacted = data.map((d: any) => `${d.style_library?.style_no}: ${d.label}`);
    return Array.from(new Set(impacted));
};

export const purgeDeletedLabels = async (section: string, labelsToKeep: string[]): Promise<void> => {
    await supabase
        .from('style_details')
        .delete()
        .eq('section', section)
        .not('label', 'in', `(${labelsToKeep.map(l => `"${l}"`).join(',')})`);
};

// --- STYLE LIBRARY API ---

export const fetchStyleLibrary = async (): Promise<StyleLibrary[]> => {
    const { data, error } = await supabase
        .from('style_library')
        .select('*, details:style_details(*)')
        .order('style_no');
    if (error) return [];
    return data || [];
};

export const upsertStyle = async (style: Partial<StyleLibrary>, details: StyleDetail[]): Promise<{ data: StyleLibrary | null, error: string | null }> => {
    const { data: styleData, error: styleError } = await supabase
        .from('style_library')
        .upsert({
            id: style.id,
            style_no: style.style_no,
            style_text: style.style_text,
            category: style.category,
            product_type: style.product_type,
            target_audience: style.target_audience,
            packing_type: style.packing_type,
            pcs_per_box: style.pcs_per_box,
            updated_at: new Date().toISOString()
        })
        .select()
        .single();

    if (styleError) return { data: null, error: styleError.message };

    if (style.id) {
        await supabase.from('style_details').delete().eq('style_id', style.id);
    }

    const detailsToInsert = details.map(d => ({
        style_id: styleData.id,
        section: d.section,
        label: d.label,
        content_text: d.content_text,
        attachments: d.attachments
    }));

    const { error: detailsError } = await supabase.from('style_details').insert(detailsToInsert);
    if (detailsError) return { data: null, error: detailsError.message };

    return { data: styleData, error: null };
};

export const deleteStyle = async (styleId: string): Promise<void> => {
    await supabase.from('style_library').delete().eq('id', styleId);
};

// --- EXISTING API ---

export const triggerOrderEmail = async (orderId: string, isEdit: boolean = false): Promise<{ success: boolean; message: string }> => {
  try {
    const response = await fetch(`${API_BASE}/api/send-email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ order_id: orderId, is_edit: isEdit })
    });
    const result = await response.json();
    return { success: response.ok, message: result.message };
  } catch (error) {
    return { success: false, message: 'Network error triggering email.' };
  }
};

export const triggerMaterialEmail = async (orderId: string): Promise<{ success: boolean; message: string }> => {
  try {
    const response = await fetch(`${API_BASE}/api/send-material-email`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ order_id: orderId })
    });
    const result = await response.json();
    return { success: response.ok, message: result.message };
  } catch (error) {
    return { success: false, message: 'Network error triggering material email.' };
  }
};

export const authenticateUser = async (username: string, password: string): Promise<AppUser | null> => {
    const { data, error } = await supabase.from('app_users').select('*').eq('username', username).eq('password', password).single();
    if (error || !data) return null;
    return { id: data.id, username: data.username, role: data.role as UserRole, full_name: data.full_name };
};

export const fetchOrderLogs = async (orderId?: string): Promise<OrderLog[]> => {
    let query = supabase.from('order_logs').select('*').order('created_at', { ascending: false });
    if (orderId) query = query.eq('order_id', orderId);
    const { data, error } = await query;
    if (error || !data) return [];
    return data as OrderLog[];
};

export const addOrderLog = async (orderId: string, type: 'STATUS_CHANGE' | 'MANUAL_UPDATE' | 'CREATION', message: string) => {
    await supabase.from('order_logs').insert([{ order_id: orderId, log_type: type, message: message, created_by_name: 'System' }]);
};

export const fetchUnits = async (): Promise<Unit[]> => {
    const { data, error } = await supabase.from('units').select('*').order('id');
    if (error || !data) return [];
    return data as Unit[];
};

export const fetchOrders = async (): Promise<Order[]> => {
  const { data, error } = await supabase.from('orders').select('*').or('deleted.eq.false,deleted.is.null').order('created_at', { ascending: false });
  if (error || !data) return [];
  return data as Order[];
};

export const createOrder = async (order: Partial<Order>): Promise<{ data: Order | null, error: string | null }> => {
    const { data: seqValue, error: seqError } = await supabase.rpc('next_order_no');
    if (seqError || !seqValue) return { data: null, error: 'Failed to generate order number' };
    const orderNo = `ORD-${seqValue}`;
    const payload: any = {
        order_no: orderNo,
        unit_id: order.unit_id,
        style_number: order.style_number,
        quantity: order.quantity,
        size_breakdown: order.size_breakdown,
        description: order.description,
        target_delivery_date: order.target_delivery_date,
        status: OrderStatus.ASSIGNED,
        deleted: false
    };
    const optionalKeys: (keyof Order)[] = ['box_count', 'size_format', 'attachments'];
    optionalKeys.forEach(key => { if (order[key] !== undefined) payload[key] = order[key]; });
    const { data, error } = await supabase.from('orders').insert([payload]).select().single();
    if (error) return { data: null, error: error.message };
    if (data) await addOrderLog(data.id, 'CREATION', `Order #${orderNo} Launched.`);
    return { data: data as Order, error: null };
};

