                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Target Audience</label><select className="w-full border-2 border-slate-100 rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.target_audience} onChange={e => setEditingStyle({...editingStyle, target_audience: e.target.value as any})}><option value="Men">Men</option><option value="Boys">Boys</option></select></div>
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1 flex justify-between">Product Type <button onClick={() => setShowNewTypeInput(!showNewTypeInput)} className="text-indigo-600 hover:underline">{showNewTypeInput ? 'Pick Standard' : 'Add New Custom'}</button></label>{showNewTypeInput ? (<input className="w-full border-2 border-slate-100 rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={customProductType} onChange={e => setCustomProductType(e.target.value)}/>) : (<select className="w-full border-2 border-slate-100 rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.product_type} onChange={e => setEditingStyle({...editingStyle, product_type: e.target.value})}>{COMMON_PRODUCT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}</select>)}</div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Packing Type</label><input className="w-full border-2 border-slate-100 rounded-2xl p-4 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.packing_type} onChange={e => setEditingStyle({...editingStyle, packing_type: e.target.value})}/></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Pcs / Box</label><input type="number" className="w-full border-2 border-slate-100 rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.pcs_per_box} onChange={e => setEditingStyle({...editingStyle, pcs_per_box: parseInt(e.target.value) || 1})}/></div>
                  </div>

                  <div className="space-y-16">
                    {template.map(sec => (
                         <div key={sec.section} className="space-y-6">
                            <div className="flex justify-between items-center border-b-2 border-slate-100 pb-3"><h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">{sec.section}</h4></div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                               {details.filter(d => d.section === sec.section).map((d, idx) => {
                                 const globalIdx = details.findIndex(gd => gd.section === d.section && gd.label === d.label);
                                 return (
                                   <div key={idx} className="group bg-slate-50/50 p-6 rounded-3xl border border-transparent hover:border-indigo-100 hover:bg-white transition-all space-y-4">
                                      <div className="text-xs font-black text-indigo-600 uppercase tracking-widest">{d.label}</div>
                                      <textarea className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm h-32 bg-white text-slate-800 font-medium focus:border-indigo-400 outline-none transition-all resize-none shadow-inner" placeholder={`Specifications for ${d.label}...`} value={d.content_text} onChange={e => { const updated = [...details]; updated[globalIdx].content_text = e.target.value; setDetails(updated); }}/>
                                      <div className="flex gap-2 flex-wrap">{d.attachments.map((a, aIdx) => (<div key={aIdx} className="group/att relative w-16 h-16 rounded-xl border border-slate-200 bg-white flex items-center justify-center shadow-sm overflow-hidden">{a.type === 'image' ? (<img src={a.url} className="w-full h-full object-cover"/>) : (<FileText size={20} className="text-slate-400"/>)}<button onClick={() => { const updated = [...details]; updated[globalIdx].attachments.splice(aIdx, 1); setDetails(updated); }} className="absolute inset-0 bg-red-600/80 text-white opacity-0 group-hover/att:opacity-100 flex items-center justify-center transition-opacity"><Trash2 size={16}/></button></div>))}<label className="w-16 h-16 rounded-xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-300 hover:border-indigo-400 hover:text-indigo-400 cursor-pointer transition-all"><Upload size={16}/><input type="file" multiple className="hidden" onChange={e => handleFileUpload(e, globalIdx)}/></label></div>
