               <button onClick={handleSave} disabled={isSubmitting} className="px-16 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">{isSubmitting ? <><Loader2 size={20} className="animate-spin"/> Syncing...</> : <><Save size={20}/> Save Master Style</>}</button>
