pan class="badge">${style.category}</span><span class="badge">${style.product_type}</span><span class="badge">${style.target_audience}</span></div></div><div style="text-align: right; font-size: 12px; color: #64748b;">Printed: ${new Date().toLocaleString()}</div></div>${sectionsHtml}</body></html>`);
    win.document.close();
    setTimeout(() => { win.print(); }, 1000);
  };

  const filteredStyles = styles.filter(s => 
    s.style_no.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.category.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.product_type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg">
              <Library size={28}/> 
            </div>
            Style Lab <span className="text-slate-300 font-light mx-2">/</span> Master Database
          </h2>
          <p className="text-slate-500 text-sm font-bold uppercase tracking-widest mt-1">Unified Technical Specifications Repository</p>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={handleOpenFormatEditor} className="flex items-center gap-2 bg-white text-slate-600 border border-slate-200 px-4 py-2.5 rounded-xl text-sm font-black hover:bg-slate-50 transition-all shadow-sm">
            <Settings2 size={18} className="text-indigo-600"/> Edit Format
          </button>
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setView('library')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'library' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid2X2 size={18}/> Library</button>
            <button onClick={() => setView('comparison')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'comparison' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Split size={18}/> Compare</button>
          </div>
