                      <div>
                        <div className="flex items-baseline gap-2">
                            <h3 className="text-2xl font-black text-slate-800">{style.style_no}</h3>
                            <span className="text-sm font-bold text-slate-400 italic">{style.style_text}</span>
                        </div>
                        <div className="flex items-center gap-3 mt-1.5">
                          <span className="text-[9px] font-black uppercase tracking-widest bg-indigo-100 text-indigo-700 px-2.5 py-1 rounded-md">{style.category}</span>
                          <span className="text-[9px] font-black uppercase tracking-widest bg-slate-100 text-slate-700 px-2.5 py-1 rounded-md">{style.product_type}</span>
