                      <div className={`p-2 rounded-full transition-transform duration-300 ${isExpanded ? 'rotate-180 bg-indigo-600 text-white' : 'text-slate-300'}`}>
                        <ChevronDown size={24}/>
                      </div>
                    </div>
                  </div>

                  {isExpanded && (
