                        const sectionDetails = style.details?.filter(d => d.section === t.section) || [];
                        return (
                          <div key={t.section} className="space-y-4">
                            <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 border-b border-slate-100 pb-2">{t.section}</h4>
                            <div className="space-y-6">
                              {t.labels.map((label, lIdx) => {
                                  const d = sectionDetails.find(sd => sd.label === label);
                                  const isTable = t.is_table_flags?.[lIdx];
                                  return (
                                    <div key={label}>
                                      <div className="text-xs font-black text-indigo-600 uppercase tracking-tight mb-1 flex items-center gap-2">
                                        {label}
                                        {isTable && <TableIcon size={12} className="opacity-40"/>}
                                      </div>
                                      {renderContent(d?.content_text || '', isTable)}
                                      {d?.attachments && d.attachments.length > 0 && (
                                        <div className="flex gap-2 mt-3 flex-wrap">
                                          {d.attachments.map((a, i) => (
                                            <a key={i} href={a.url} target="_blank" rel="noreferrer" className="w-10 h-10 rounded-lg border border-slate-200 bg-slate-50 flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:border-indigo-200 transition-all" title={a.name}>
                                              {a.type === 'image' ? <ImageIcon size={14}/> : <FileText size={14}/>}
                                            </a>
                                          ))}
                                        </div>
                                      )}
                                    </div>
                                  );
                              })}
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })
          )}
        </div>
      )}

