import { supabase } from './supabase';
import { Order, OrderStatus, MaterialRequest, Barcode, BarcodeStatus, Unit, MaterialStatus, Invoice, SizeBreakdown, AppUser, UserRole, StockCommit, MaterialApproval, OrderLog, Attachment, StyleLibrary, StyleDetail, StyleTemplate } from '../types';

const API_BASE = (typeof window !== 'undefined' && (window.location.protocol === 'file:' || window.location.hostname === 'localhost'))
  ? 'https://tintura-mail.vercel.app'
  : '';

// --- STYLE TEMPLATE API ---

export const fetchStyleTemplate = async (): Promise<StyleTemplate[]> => {
    const { data, error } = await supabase
        .from('style_template')
        .select('*')
        .order('display_order');
    if (error) return [];
    return data || [];
};

export const saveStyleTemplate = async (template: StyleTemplate[]): Promise<{ success: boolean; error?: string }> => {
    try {
        // 1. Wipe current template completely to avoid primary key conflicts or abandoned rows
        const { error: delError } = await supabase
            .from('style_template')
            .delete()
            .not('section', 'is', null); // Standard way to delete all rows

        if (delError) throw delError;

        // 2. Insert new configuration
        if (template.length > 0) {
            const { error: insError } = await supabase
                .from('style_template')
                .insert(template.map((t, i) => ({
                    section: t.section,
                    labels: t.labels || [],
                    is_table_flags: t.is_table_flags || new Array(t.labels?.length || 0).fill(false),
                    display_order: i + 1
                })));
            if (insError) throw insError;
        }
        return { success: true };
    } catch (e: any) {
        console.error("Template Sync Failed:", e);
        return { success: false, error: e.message };
    }
};

export const checkTemplateDeletionImpact = async (section: string, labels: string[]): Promise<string[]> => {
    const { data, error } = await supabase
        .from('style_details')
        .select('label, style_library(style_no)')
        .eq('section', section)
        .not('label', 'in', `(${labels.map(l => `"${l}"`).join(',')})`);

    if (error || !data) return [];

    const impacted = data
        .filter((d: any) => d.content_text || (d.attachments && d.attachments.length > 0))
        .map((d: any) => `${d.style_library?.style_no}: ${d.label}`);

    return Array.from(new Set(impacted));
};

export const purgeDeletedLabels = async (section: string, labelsToKeep: string[]): Promise<void> => {
    await supabase
        .from('style_details')
        .delete()
        .eq('section', section)
        .not('label', 'in', `(${labelsToKeep.map(l => `"${l}"`).join(',')})`);
};

export const deleteTemplateSection = async (section: string): Promise<void> => {
    await supabase.from('style_details').delete().eq('section', section);
};

// --- STYLE LIBRARY API ---

export const fetchStyleLibrary = async (): Promise<StyleLibrary[]> => {
    const { data, error } = await supabase
        .from('style_library')
        .select('*, details:style_details(*)')
        .order('style_no');
    if (error) return [];
    return data || [];
};

export const upsertStyle = async (style: Partial<StyleLibrary>, details: StyleDetail[]): Promise<{ data: StyleLibrary | null, error: string | null }> => {
    const { data: styleData, error: styleError } = await supabase
        .from('style_library')
        .upsert({
            id: style.id,
            style_no: style.style_no,
            style_text: style.style_text,
            category: style.category,
            product_type: style.product_type,
            target_audience: style.target_audience,
            packing_type: style.packing_type,
            pcs_per_box: style.pcs_per_box,
            updated_at: new Date().toISOString()
        })
        .select()
        .single();

    if (styleError) return { data: null, error: styleError.message };

    // Clean up old details for this specific style
    if (styleData.id) {
        await supabase.from('style_details').delete().eq('style_id', styleData.id);
    }

    if (details.length > 0) {
        const detailsToInsert = details.map(d => ({
            style_id: styleData.id,
            section: d.section,
            label: d.label,
            content_text: d.content_text,
            attachments: d.attachments || []
        }));

        const { error: detailsError } = await supabase.from('style_details').insert(detailsToInsert);
        if (detailsError) return { data: null, error: detailsError.message };
    }

    return { data: styleData, error: null };
};

export const deleteStyle = async (styleId: string): Promise<{ success: boolean; error?: string }> => {
    try {
        // Even with CASCADE delete in SQL, we manually clear details first for extra safety
        const { error: detailsError } = await supabase
            .from('style_details')
            .delete()
            .eq('style_id', styleId);

        if (detailsError) throw detailsError;

        // Delete the master record
        const { error: styleError } = await supabase
            .from('style_library')
            .delete()
            .eq('id', styleId);

        if (styleError) throw styleError;

        return { success: true };
    } catch (e: any) {
        console.error("Master Style Deletion Failed:", e);
        return { success: false, error: e.message };
    }
};

