export const fetchBarcodesBySerialList = async (serials: string[]): Promise<Barcode[]> => {
    if (serials.length === 0) return [];
    const { data, error } = await supabase.from('barcodes').select('*').in('barcode_serial', serials);
    if (error || !data) return [];
    return data as Barcode[];
};

export const generateBarcodes = async (orderId: string, count: number, style: string, size: string) => {
    const orderRes = await supabase.from('orders').select('order_no, last_barcode_serial').eq('id', orderId).single();
    if (orderRes.error || !orderRes.data) return [];
    let currentSerial = orderRes.data.last_barcode_serial || 0;
    const newBarcodes = [];
    for (let i = 1; i <= count; i++) {
        currentSerial++;
        newBarcodes.push({
            barcode_serial: `${orderRes.data.order_no};${style};${size};${currentSerial.toString().padStart(5, '0')}`,
            order_id: orderId, style_number: style, size: size, status: BarcodeStatus.GENERATED
        });
    }
    await supabase.from('barcodes').insert(newBarcodes);
    await supabase.from('orders').update({ last_barcode_serial: currentSerial }).eq('id', orderId);
    return newBarcodes as any[];
};

export const commitBarcodesToStock = async (serials: string[]) => {
    const { data: commitData, error: commitError } = await supabase.from('stock_commits').insert([{ total_items: serials.length }]).select().single();
    if (commitError) return;
    await supabase.from('barcodes').update({ status: BarcodeStatus.COMMITTED_TO_STOCK, commit_id: commitData.id }).in('barcode_serial', serials);
};

export const fetchStockCommits = async (): Promise<StockCommit[]> => {
    const { data, error } = await supabase.from('stock_commits').select('*').order('created_at', { ascending: false });
    if (error || !data) return [];
    return data as StockCommit[];
};

export const fetchBarcodesByCommit = async (commitId: number): Promise<Barcode[]> => {
    const { data, error } = await supabase.from('barcodes').select('*').eq('commit_id', commitId);
    if (error || !data) return [];
    return data as Barcode[];
};

export const fetchInvoices = async (): Promise<Invoice[]> => {
    const { data, error } = await supabase.from('invoices').select('*').order('created_at', { ascending: false });
    if (error || !data) return [];
    return data as Invoice[];
};

export const fetchInvoiceItems = async (invoiceId: string): Promise<Barcode[]> => {
    const { data, error } = await supabase.from('barcodes').select('*').eq('invoice_id', invoiceId);
    if (error || !data) return [];
    return data as Barcode[];
}

export const createInvoice = async (customerName: string, barcodeIds: string[], customInvoiceNo?: string): Promise<Invoice> => {
    const invoiceNo = customInvoiceNo || `INV-${Date.now()}`;
    const { data: invData, error: invError } = await supabase.from('invoices').insert([{ invoice_no: invoiceNo, customer_name: customerName, total_amount: barcodeIds.length * 25.00 }]).select().single();
    if (invError) throw invError;
    await supabase.from('barcodes').update({ status: BarcodeStatus.SOLD, invoice_id: invData.id }).in('id', barcodeIds);
    return invData as Invoice;
};

export const uploadOrderAttachment = async (file: File): Promise<string | null> => {
    const fileExt = file.name.split('.').pop();
    const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
    const { error } = await supabase.storage.from('order-attachments').upload(fileName, file);
    if (error) return null;
    const { data } = supabase.storage.from('order-attachments').getPublicUrl(fileName);
    return data.publicUrl;
};

import React, { useEffect, useState } from 'react';
import { fetchStyleLibrary, upsertStyle, deleteStyle, uploadOrderAttachment, fetchStyleTemplate, saveStyleTemplate, checkTemplateDeletionImpact, purgeDeletedLabels, deleteTemplateSection } from '../services/db';
import { StyleLibrary, StyleDetail, Attachment, StyleTemplate } from '../types';
import { 
  Library, Search, Plus, Trash2, Copy, Printer, ChevronDown, ChevronRight, X, Upload, FileText, Image as ImageIcon, Save, Loader2, Split, Grid2X2, AlertCircle, Download, MoreVertical, Layers, Users, Settings2, GripVertical, Table as TableIcon, List as ListIcon, LayoutPanelTop
} from 'lucide-react';

const COMMON_PRODUCT_TYPES = ['T-shirt', 'Pant', 'Shorts', 'Shirt', 'Innerwear', 'Sweatshirt', 'Hoodie'];

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<StyleLibrary[]>([]);
  const [template, setTemplate] = useState<StyleTemplate[]>([]);
  const [view, setView] = useState<'library' | 'comparison'>('library');
  const [searchTerm, setSearchTerm] = useState('');
  const [loading, setLoading] = useState(true);
  const [expandedStyles, setExpandedStyles] = useState<string[]>([]);
  const [selectedForCompare, setSelectedForCompare] = useState<string[]>([]);

  // Modal States
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isFormatEditorOpen, setIsFormatEditorOpen] = useState(false);
  const [editingStyle, setEditingStyle] = useState<Partial<StyleLibrary> | null>(null);
  const [details, setDetails] = useState<StyleDetail[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isCopying, setIsCopying] = useState(false);

  // Format Editor Local State
  const [localTemplate, setLocalTemplate] = useState<StyleTemplate[]>([]);

  // Custom Product Type handling
  const [showNewTypeInput, setShowNewTypeInput] = useState(false);
  const [customProductType, setCustomProductType] = useState('');

  const loadData = async () => {
    setLoading(true);
    try {
        const [libData, tempData] = await Promise.all([
            fetchStyleLibrary(),
            fetchStyleTemplate()
        ]);
        // COMPLETELY ISOLATE 'General Info' from dynamic template logic
        const filteredTemplate = tempData.filter(t => t.section !== 'General Info');
        setStyles(libData);
        setTemplate(filteredTemplate);
    } catch (e) {
        console.error("Style Database Load Failed:", e);
    } finally {
        setLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const toggleExpand = (id: string) => {
    setExpandedStyles(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const prepareDetailsForStyle = (styleDetails: StyleDetail[] = []) => {
      const merged: StyleDetail[] = [];
      template.forEach(t => {
          t.labels.forEach((label, idx) => {
              const existing = styleDetails.find(d => d.section === t.section && d.label === label);
              const isTable = t.is_table_flags?.[idx] || false;

              let content = existing?.content_text || '';
              if (isTable && (!content || content === '')) {
                  content = JSON.stringify([['', '']]);
              }

              merged.push(existing || { section: t.section, label, content_text: content, attachments: [] });
          });
      });
      return merged;
  };

  const handleOpenCreate = () => {
    setEditingStyle({ 
        style_no: '', style_text: '', category: 'Casuals', product_type: 'T-shirt', target_audience: 'Men', pcs_per_box: 1, packing_type: 'cover' 
    });
    setDetails(prepareDetailsForStyle([]));
    setIsEditorOpen(true);
    setShowNewTypeInput(false);
  };

  const handleEdit = (style: StyleLibrary) => {
    setEditingStyle(style);
    setDetails(prepareDetailsForStyle(style.details));
    setIsEditorOpen(true);
    setShowNewTypeInput(!COMMON_PRODUCT_TYPES.includes(style.product_type));
  };

  const handleCopyFrom = (sourceStyle: StyleLibrary) => {
    if (!editingStyle) return;
    const copiedDetails = sourceStyle.details?.map(d => ({
      ...d, id: undefined, style_id: undefined
    })) || [];
    setDetails(prepareDetailsForStyle(copiedDetails));
    setIsCopying(false);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, detailIndex: number) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    const updated = [...details];
    for (const file of Array.from(files) as File[]) {
      const url = await uploadOrderAttachment(file);
      if (url) {
        updated[detailIndex].attachments.push({
          name: file.name, url, type: (file.type.startsWith('image/') ? 'image' : 'document') as 'image' | 'document'
        });
      }
    }
    setDetails(updated);
  };

  const handleSave = async () => {
    if (!editingStyle?.style_no) return alert("Style Number is required");
    setIsSubmitting(true);
    try {
        const finalStyle = { ...editingStyle, product_type: showNewTypeInput ? customProductType : editingStyle.product_type };
        const result = await upsertStyle(finalStyle, details);
        if (result.error) alert(`Save failed: ${result.error}`);
        else { setIsEditorOpen(false); await loadData(); }
    } catch(e: any) {
        alert(`Error: ${e.message}`);
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleDelete = async (styleId: string) => {
    if (!styleId) return;
    if (!confirm("Are you ABSOLUTELY sure? Deleting this Master Style will erase all technical data, tables, and images for this style number. This cannot be undone.")) return;

    setLoading(true);
    try {
        const result = await deleteStyle(styleId);
        if (result.success) {
            await loadData();
            setExpandedStyles(prev => prev.filter(id => id !== styleId));
        } else {
            alert(`Could not delete style: ${result.error}`);
        }
    } catch (e: any) {
        alert(`Deletion Error: ${e.message}`);
    } finally {
        setLoading(false);
    }
  };

  // --- FORMAT EDITOR LOGIC ---
  const handleOpenFormatEditor = () => {
      setLocalTemplate(JSON.parse(JSON.stringify(template)));
      setIsFormatEditorOpen(true);
  };

  const addSectionToTemplate = () => {
      const name = prompt("Enter Section Name (e.g., Fabric Specifications):");
      if (!name) return;
      if (localTemplate.some(t => t.section === name)) return alert("Section already exists.");
      setLocalTemplate([...localTemplate, { id: Date.now().toString(), section: name, labels: [], is_table_flags: [], display_order: localTemplate.length + 1 }]);
  };

  const removeSectionFromTemplate = async (sIdx: number) => {
      const section = localTemplate[sIdx].section;
      if (!confirm(`Delete ENTIRE section "${section}"? This will remove all its fields from all styles upon save.`)) return;

      const updated = [...localTemplate];
      updated.splice(sIdx, 1);
      setLocalTemplate(updated);
  };

  const addLabelToTemplate = (sectionIndex: number) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels.push('New Specification Field');
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      } else {
          updated[sectionIndex].is_table_flags.push(false);
      }
      setLocalTemplate(updated);
  };

  const updateLabelInTemplate = (sectionIndex: number, labelIndex: number, val: string) => {
      const updated = [...localTemplate];
      updated[sectionIndex].labels[labelIndex] = val;
      setLocalTemplate(updated);
  };

  const toggleTableFlag = (sectionIndex: number, labelIndex: number) => {
      const updated = [...localTemplate];
      if (!updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags = new Array(updated[sectionIndex].labels.length).fill(false);
      }
      updated[sectionIndex].is_table_flags[labelIndex] = !updated[sectionIndex].is_table_flags[labelIndex];
      setLocalTemplate(updated);
  };

  const removeLabelFromTemplate = (sectionIndex: number, labelIndex: number) => {
      const label = localTemplate[sectionIndex].labels[labelIndex];
      if (!confirm(`Remove field "${label}"? This is permanent.`)) return;
      const updated = [...localTemplate];
      updated[sectionIndex].labels.splice(labelIndex, 1);
      if (updated[sectionIndex].is_table_flags) {
          updated[sectionIndex].is_table_flags.splice(labelIndex, 1);
      }
      setLocalTemplate(updated);
  };

  const handleSaveTemplate = async () => {
      setIsSubmitting(true);
      try {
          const originalSections = template.map(t => t.section);
          const currentSections = localTemplate.map(t => t.section);
          const removedSections = originalSections.filter(s => !currentSections.includes(s));

          for (const rs of removedSections) {
              await deleteTemplateSection(rs);
          }

          for (const section of localTemplate) {
              const oldSection = template.find(t => t.section === section.section);
              if (oldSection) {
                  const deletedLabels = oldSection.labels.filter(l => !section.labels.includes(l));
                  if (deletedLabels.length > 0) {
                      const impact = await checkTemplateDeletionImpact(section.section, section.labels);
                      if (impact.length > 0) {
                          const confirmDelete = confirm(`WARNING: Removing fields in "${section.section}" will delete data for styles:\n\n${impact.join('\n')}\n\nContinue?`);
                          if (!confirmDelete) { setIsSubmitting(false); return; }
                          await purgeDeletedLabels(section.section, section.labels);
                      }
                  }
              }
          }

          const result = await saveStyleTemplate(localTemplate);
          if (!result.success) {
            alert(`Template Save Error: ${result.error}`);
          } else {
            setIsFormatEditorOpen(false);
            await loadData();
          }
      } catch (e: any) {
          alert(`Template Save Exception: ${e.message}`);
      } finally {
          setIsSubmitting(false);
      }
  };

  const renderContent = (content: string, isTable: boolean) => {
      if (isTable) {
          try {
              const data = JSON.parse(content) as string[][];
