      }
      return <div className="text-sm font-medium text-slate-600 leading-relaxed whitespace-pre-wrap">{content || '---'}</div>;
  };

  const handlePrintStyle = (style: StyleLibrary) => {
    const win = window.open('', 'PrintStyle', 'width=1000,height=800');
    if (!win) return;
    const sectionsHtml = template.map(t => {
      const sectionDetails = style.details?.filter(d => d.section === t.section) || [];
