            <button onClick={() => setView('comparison')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-black transition-all ${view === 'comparison' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Split size={18}/> Compare</button>
          </div>
          <button onClick={handleOpenCreate} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black shadow-xl shadow-indigo-200 flex items-center gap-2 hover:bg-indigo-700 active:scale-95 transition-all">
            <Plus size={20}/> Add Master Style
          </button>
        </div>
      </div>

      <div className="relative max-w-xl">
        <input 
          type="text" 
          placeholder="Search by Style No, Text or Type..." 
          className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-300 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none text-lg font-medium shadow-sm transition-all bg-white text-slate-900"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <Search className="absolute left-4 top-4.5 text-slate-400" size={24}/>
      </div>

      {view === 'library' && (
        <div className="space-y-4 animate-fade-in">
          {loading ? (
            <div className="p-20 text-center text-slate-400 font-bold uppercase tracking-widest flex flex-col items-center gap-4">
              <Loader2 className="animate-spin text-indigo-600" size={48}/>
              Scanning Library...
