                <div key={style.id} className="w-[450px] shrink-0 bg-white rounded-3xl border-2 border-indigo-100 shadow-2xl overflow-hidden flex flex-col max-h-[85vh] animate-scale-up">
                   <div className="p-6 bg-indigo-600 text-white flex justify-between items-start">
                      <div>
                        <h4 className="text-3xl font-black tracking-tight">{style.style_no}</h4>
                        <div className="flex gap-2 mt-1">
