                   </div>
                   <div className="p-4 border-t bg-slate-50 flex justify-between">
                      <button onClick={() => handlePrintStyle(style)} className="flex-1 flex items-center justify-center gap-2 font-black text-xs text-indigo-600 uppercase tracking-widest hover:bg-white py-3 rounded-xl transition-all"><Printer size={16}/> Full Print</button>
                   </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {isFormatEditorOpen && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md">
