                    <div>
                        <h3 className="text-3xl font-black text-slate-800 tracking-tight">Technical Specification Blueprint</h3>
                        <p className="text-slate-400 text-xs font-black uppercase tracking-widest mt-1">Configure global fields and sections for all Styles</p>
                    </div>
                    <button onClick={() => setIsFormatEditorOpen(false)} className="text-slate-300 hover:text-slate-600 transition-colors p-2 hover:bg-slate-100 rounded-full"><X size={40}/></button>
                </div>

                <div className="flex-1 overflow-y-auto p-10 space-y-12 bg-slate-50/20">
                    {localTemplate.map((sec, sIdx) => (
                        <div key={sIdx} className="space-y-4 bg-white p-6 rounded-3xl border border-slate-200 shadow-sm relative group/sec">
                            <div className="flex items-center justify-between border-b-2 border-indigo-100 pb-3">
                                <div className="flex items-center gap-4">
                                    <LayoutPanelTop size={24} className="text-indigo-600"/>
                                    <input 
