                                                onChange={(e) => updateLabelInTemplate(sIdx, lIdx, e.target.value)}
                                            />
                                            <button 
                                                onClick={() => toggleTableFlag(sIdx, lIdx)}
                                                className={`p-1.5 rounded-lg transition-all ${sec.is_table_flags?.[lIdx] ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-300 hover:bg-slate-200'}`}
                                                title="Toggle Table Mode"
                                            >
                                                <TableIcon size={14}/>
                                            </button>
                                            <button onClick={() => removeLabelFromTemplate(sIdx, lIdx)} className="p-1.5 text-slate-200 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all">
                                                <Trash2 size={14}/>
                                            </button>
                                        </div>
                                        {sec.is_table_flags?.[lIdx] && <span className="text-[9px] font-black text-indigo-500 uppercase flex items-center gap-1"><TableIcon size={8}/> Dynamic Table Mode</span>}
                                    </div>
                                ))}
                                <button 
                                    onClick={() => addLabelToTemplate(sIdx)}
                                    className="border-2 border-dashed border-slate-200 rounded-2xl p-3 text-slate-400 hover:border-indigo-400 hover:text-indigo-600 hover:bg-white transition-all flex items-center justify-center gap-2 text-xs font-black uppercase"
                                >
                                    <Plus size={16}/> Add Specification
                                </button>
                            </div>
                        </div>
                    ))}

                    <button 
                        onClick={addSectionToTemplate}
                        className="w-full border-4 border-dashed border-slate-200 rounded-3xl p-8 text-slate-400 hover:border-indigo-400 hover:text-indigo-600 hover:bg-white transition-all flex flex-col items-center justify-center gap-3 group"
                    >
                        <LayoutPanelTop size={48} className="opacity-20 group-hover:opacity-100 group-hover:scale-110 transition-transform"/>
                        <span className="font-black uppercase tracking-widest text-sm">Add New Technical Section</span>
                    </button>
                </div>

                <div className="p-8 border-t bg-slate-50 flex justify-end gap-4">
                    <button onClick={() => setIsFormatEditorOpen(false)} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 hover:bg-white rounded-2xl transition-all uppercase tracking-widest text-xs">Discard Changes</button>
                    <button onClick={handleSaveTemplate} disabled={isSubmitting} className="px-16 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">
                        {isSubmitting ? <><Loader2 size={20} className="animate-spin"/> Synchronizing Database...</> : <><Save size={20}/> Save Global Template</>}
                    </button>
                </div>
            </div>
        </div>
      )}

      {isEditorOpen && editingStyle && (
        <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
            <div className="p-8 border-b bg-slate-50 flex justify-between items-center">
              <div>
                <h3 className="text-3xl font-black text-slate-800 tracking-tight">{editingStyle.id ? 'Edit Master Style' : 'New Master Style Entry'}</h3>
                <p className="text-slate-400 text-xs font-black uppercase tracking-widest mt-1">Populating manufacturing technical standard</p>
              </div>
              <div className="flex items-center gap-4">
                <button onClick={() => setIsCopying(!isCopying)} className="bg-indigo-50 text-indigo-600 border border-indigo-200 px-6 py-3 rounded-2xl text-sm font-black flex items-center gap-2 hover:bg-indigo-100 transition-all"><Copy size={20}/> {isCopying ? 'Cancel Cloning' : 'Clone Specifications'}</button>
                <button onClick={() => setIsEditorOpen(false)} className="text-slate-300 hover:text-slate-600 transition-colors p-2 hover:bg-slate-100 rounded-full"><X size={40}/></button>
              </div>
            </div>

            <div className="flex-1 flex overflow-hidden">
               {isCopying && (
                 <div className="w-80 border-r border-slate-200 bg-slate-50 p-6 overflow-y-auto animate-fade-in shrink-0">
                    <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6">Select Template Source</h4>
                    <div className="space-y-3">
                       {styles.map(s => (<button key={s.id} onClick={() => handleCopyFrom(s)} className="w-full text-left p-4 bg-white rounded-2xl border border-slate-200 hover:border-indigo-500 hover:shadow-lg transition-all group"><div className="font-black text-lg text-slate-700 group-hover:text-indigo-600">{s.style_no}</div><div className="text-[10px] font-bold text-slate-400">{s.category} • {s.product_type}</div></button>))}
                    </div>
                 </div>
               )}

               <div className="flex-1 overflow-y-auto p-10 space-y-12">
                  <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-6 bg-slate-50 p-8 rounded-[30px] border border-slate-200 shadow-inner">
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Style Reference No.</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 text-xl font-black focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" value={editingStyle.style_no} onChange={e => setEditingStyle({...editingStyle, style_no: e.target.value})}/></div>
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Description Text</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm" value={editingStyle.style_text} onChange={e => setEditingStyle({...editingStyle, style_text: e.target.value})}/></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Category</label><select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.category} onChange={e => setEditingStyle({...editingStyle, category: e.target.value as any})}><option value="Casuals">Casuals</option><option value="Lite">Lite</option><option value="Sportz">Sportz</option></select></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Audience</label><select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.target_audience} onChange={e => setEditingStyle({...editingStyle, target_audience: e.target.value as any})}><option value="Men">Men</option><option value="Boys">Boys</option></select></div>
                    <div className="lg:col-span-2"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1 flex justify-between">Product Type <button onClick={() => setShowNewTypeInput(!showNewTypeInput)} className="text-indigo-600 hover:underline">{showNewTypeInput ? 'Standard' : 'Custom'}</button></label>{showNewTypeInput ? (<input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={customProductType} onChange={e => setCustomProductType(e.target.value)}/>) : (<select className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.product_type} onChange={e => setEditingStyle({...editingStyle, product_type: e.target.value})}>{COMMON_PRODUCT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}</select>)}</div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Packing</label><input className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-bold focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.packing_type} onChange={e => setEditingStyle({...editingStyle, packing_type: e.target.value})}/></div>
                    <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Pcs / Box</label><input type="number" className="w-full border-2 border-white rounded-2xl p-4 bg-white text-slate-900 font-black focus:ring-4 focus:ring-indigo-500/10 outline-none shadow-sm" value={editingStyle.pcs_per_box} onChange={e => setEditingStyle({...editingStyle, pcs_per_box: parseInt(e.target.value) || 1})}/></div>
                  </div>

                  <div className="space-y-16">
                    {template.map(sec => (
                         <div key={sec.section} className="space-y-6">
                            <div className="flex justify-between items-center border-b-2 border-slate-100 pb-3"><h4 className="text-xl font-black text-slate-800 uppercase tracking-tight">{sec.section}</h4></div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                               {template.find(t => t.section === sec.section)?.labels.map((label, lIdx) => {
                                 const globalIdx = details.findIndex(gd => gd.section === sec.section && gd.label === label);
                                 const d = details[globalIdx];
                                 const isTable = sec.is_table_flags?.[lIdx];

                                 return (
                                   <div key={label} className="group bg-slate-50/50 p-6 rounded-[30px] border border-transparent hover:border-indigo-100 hover:bg-white transition-all space-y-4">
                                      <div className="text-xs font-black text-indigo-600 uppercase tracking-widest flex items-center justify-between">
                                        {label}
                                        {isTable && <TableIcon size={14} className="opacity-50"/>}
                                      </div>

                                      {isTable ? (
                                        <div className="space-y-2">
                                          {(() => {
                                            let tableData: string[][] = [['', '']];
                                            try { tableData = JSON.parse(d.content_text); } catch(e) { }
                                            return tableData.map((row, rowIdx) => (
                                              <div key={rowIdx} className="flex gap-2 animate-fade-in">
                                                <input className="w-1/3 border border-slate-200 rounded-xl p-3 text-xs font-bold bg-white" placeholder="Key" value={row[0]} onChange={e => {
                                                  const newTable = [...tableData];
                                                  newTable[rowIdx][0] = e.target.value;
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }}/>
                                                <input className="flex-1 border border-slate-200 rounded-xl p-3 text-xs bg-white" placeholder="Value" value={row[1]} onChange={e => {
                                                  const newTable = [...tableData];
                                                  newTable[rowIdx][1] = e.target.value;
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }}/>
                                                <button onClick={() => {
                                                  if (tableData.length === 1) return;
                                                  const newTable = tableData.filter((_, i) => i !== rowIdx);
                                                  const updated = [...details];
                                                  updated[globalIdx].content_text = JSON.stringify(newTable);
                                                  setDetails(updated);
                                                }} className="p-2 text-slate-300 hover:text-red-500"><X size={14}/></button>
                                              </div>
                                            ));
                                          })()}
                                          <button onClick={() => {
                                            let tableData = [['', '']];
                                            try { tableData = JSON.parse(d.content_text); } catch(e) {}
                                            const updated = [...details];
                                            updated[globalIdx].content_text = JSON.stringify([...tableData, ['', '']]);
                                            setDetails(updated);
                                          }} className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-100">+ Add Row Entry</button>
                                        </div>
                                      ) : (
                                        <textarea className="w-full border-2 border-slate-100 rounded-3xl p-6 text-sm h-32 bg-white text-slate-800 font-medium focus:border-indigo-400 outline-none transition-all resize-none shadow-inner" placeholder={`Provide technical specifications for ${label}...`} value={d.content_text} onChange={e => { const updated = [...details]; updated[globalIdx].content_text = e.target.value; setDetails(updated); }}/>
                                      )}

                                      <div className="flex gap-2 flex-wrap pt-2">
                                        {d.attachments.map((a, aIdx) => (
                                            <div key={aIdx} className="group/att relative w-16 h-16 rounded-2xl border border-slate-200 bg-white flex items-center justify-center shadow-sm overflow-hidden">
                                                {a.type === 'image' ? <img src={a.url} className="w-full h-full object-cover"/> : <FileText size={24} className="text-slate-400"/>}
                                                <button onClick={() => { const updated = [...details]; updated[globalIdx].attachments.splice(aIdx, 1); setDetails(updated); }} className="absolute inset-0 bg-red-600/80 text-white opacity-0 group-hover/att:opacity-100 flex items-center justify-center transition-opacity"><Trash2 size={20}/></button>
                                            </div>
                                        ))}
                                        <label className="w-16 h-16 rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-300 hover:border-indigo-400 hover:text-indigo-400 cursor-pointer transition-all">
                                            <Upload size={20}/><input type="file" multiple className="hidden" onChange={e => handleFileUpload(e, globalIdx)}/>
                                        </label>
                                      </div>
                                   </div>);
                               })}
                            </div>
                         </div>
                    ))}
                  </div>
               </div>
            </div>

            <div className="p-8 border-t bg-slate-50 flex justify-end gap-4 shadow-[0_-10px_20px_rgba(0,0,0,0.03)]">
               <button onClick={() => setIsEditorOpen(false)} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 hover:bg-white rounded-2xl transition-all uppercase tracking-widest text-xs">Discard</button>
               <button onClick={handleSave} disabled={isSubmitting} className="px-16 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 hover:bg-indigo-700 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">{isSubmitting ? <><Loader2 size={20} className="animate-spin"/> Transmitting...</> : <><Save size={20}/> Save Master Style</>}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { supabase } from './supabase';
import { Order, OrderStatus, MaterialRequest, Barcode, BarcodeStatus, Unit, MaterialStatus, Invoice, SizeBreakdown, AppUser, UserRole, StockCommit, MaterialApproval, OrderLog, Attachment, StyleLibrary, StyleDetail, StyleTemplate } from '../types';

const API_BASE = (typeof window !== 'undefined' && (window.location.protocol === 'file:' || window.location.hostname === 'localhost'))
  ? 'https://tintura-mail.vercel.app'
  : '';

// --- STYLE TEMPLATE API ---

export const fetchStyleTemplate = async (): Promise<StyleTemplate[]> => {
    const { data, error } = await supabase
        .from('style_template')
        .select('*')
        .order('display_order');
    if (error) return [];
    return data || [];
};

export const saveStyleTemplate = async (template: StyleTemplate[]): Promise<{ success: boolean; error?: string }> => {
    try {
        // 1. Wipe current template completely to avoid primary key conflicts or abandoned rows
        const { error: delError } = await supabase
            .from('style_template')
            .delete()
            .not('section', 'is', null); 

        if (delError) throw delError;

        // 2. Insert new configuration
        if (template.length > 0) {
            const { error: insError } = await supabase
                .from('style_template')
                .insert(template.map((t, i) => ({
                    section: t.section,
                    labels: t.labels || [],
                    is_table_flags: t.is_table_flags || new Array(t.labels?.length || 0).fill(false),
                    display_order: i + 1
                })));
            if (insError) throw insError;
        }
        return { success: true };
    } catch (e: any) {
        console.error("Template Sync Failed:", e);
        return { success: false, error: e.message };
    }
};

export const checkTemplateDeletionImpact = async (section: string, labels: string[]): Promise<string[]> => {
    const { data, error } = await supabase
        .from('style_details')
        .select('label, style_library(style_no)')
        .eq('section', section)
        .not('label', 'in', `(${labels.map(l => `"${l}"`).join(',')})`);

    if (error || !data) return [];

    const impacted = data
        .filter((d: any) => d.content_text || (d.attachments && d.attachments.length > 0))
        .map((d: any) => `${d.style_library?.style_no}: ${d.label}`);

    return Array.from(new Set(impacted));
};

export const purgeDeletedLabels = async (section: string, labelsToKeep: string[]): Promise<void> => {
    await supabase
        .from('style_details')
        .delete()
        .eq('section', section)
        .not('label', 'in', `(${labelsToKeep.map(l => `"${l}"`).join(',')})`);
};

export const deleteTemplateSection = async (section: string): Promise<void> => {
    await supabase.from('style_details').delete().eq('section', section);
};

// --- STYLE LIBRARY API ---

export const fetchStyleLibrary = async (): Promise<StyleLibrary[]> => {
    const { data, error } = await supabase
        .from('style_library')
        .select('*, details:style_details(*)')
        // ONLY FETCH NON-DELETED STYLES
        .or('is_deleted.eq.false,is_deleted.is.null')
        .order('style_no');
    if (error) return [];
    return data || [];
};

export const upsertStyle = async (style: Partial<StyleLibrary>, details: StyleDetail[]): Promise<{ data: StyleLibrary | null, error: string | null }> => {
    const { data: styleData, error: styleError } = await supabase
        .from('style_library')
        .upsert({
            id: style.id,
            style_no: style.style_no,
            style_text: style.style_text,
            category: style.category,
            product_type: style.product_type,
            target_audience: style.target_audience,
            packing_type: style.packing_type,
            pcs_per_box: style.pcs_per_box,
            is_deleted: false, // Ensure it's active on save
            updated_at: new Date().toISOString()
        })
        .select()
        .single();

    if (styleError) return { data: null, error: styleError.message };

    // Clean up old details for this specific style
    if (styleData.id) {
        await supabase.from('style_details').delete().eq('style_id', styleData.id);
    }

    if (details.length > 0) {
        const detailsToInsert = details.map(d => ({
            style_id: styleData.id,
            section: d.section,
            label: d.label,
            content_text: d.content_text,
            attachments: d.attachments || []
        }));

        const { error: detailsError } = await supabase.from('style_details').insert(detailsToInsert);
        if (detailsError) return { data: null, error: detailsError.message };
    }

    return { data: styleData, error: null };
};

export const deleteStyle = async (styleId: string): Promise<{ success: boolean; error?: string }> => {
    try {
        // SOFT DELETE: Update is_deleted flag instead of removing record
        const { error: styleError } = await supabase
            .from('style_library')
            .update({ is_deleted: true })
            .eq('id', styleId);

        if (styleError) throw styleError;

        return { success: true };
    } catch (e: any) {
        console.error("Master Style Soft-Deletion Failed:", e);
        return { success: false, error: e.message };
    }
};

